import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { 
  BarChart3, 
  LineChart, 
  PieChart, 
  Zap, 
  Loader, 
  AlertCircle,
  Play,
  Eye,
  Code,
  Download
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import aiChatService from '../services/aiChatService';

// Consistent color palette and styling
const theme = {
  primaryGradient: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
  secondaryGradient: 'linear-gradient(135deg, #f0f9ff 0%, #e0f2fe 100%)',
  successGradient: 'linear-gradient(135deg, #f0fdf4 0%, #dcfce7 100%)',
  cardBackground: 'white',
  borderColor: '#e2e8f0',
  boxShadow: '0 4px 15px rgba(0, 0, 0, 0.05)',
  borderRadius: '1rem',
  textColor: '#1e293b',
  secondaryTextColor: '#64748b'
};

// Container with responsive design
const Container = styled.div`
  padding: 2rem;
  background: linear-gradient(135deg, #f0f4f8 0%, #e6f7ff 100%);
  min-height: 100vh;
  position: relative;
  overflow: hidden;
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: radial-gradient(circle at center, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0) 70%);
    z-index: 0;
  }
  
  @media (max-width: 768px) {
    padding: 1rem;
  }
  
  @media (max-width: 480px) {
    padding: 0.5rem;
  }
`;

const Header = styled.div`
  margin-bottom: 2rem;
  position: relative;
  z-index: 1;
`;

const Title = styled.h1`
  font-size: 2rem;
  font-weight: 700;
  color: ${theme.textColor};
  margin-bottom: 0.5rem;
  
  @media (max-width: 768px) {
    font-size: 1.75rem;
  }
  
  @media (max-width: 480px) {
    font-size: 1.5rem;
  }
`;

const Subtitle = styled.p`
  color: ${theme.secondaryTextColor};
  font-size: 1.1rem;
  
  @media (max-width: 480px) {
    font-size: 0.9rem;
  }
`;

const Section = styled.div`
  background: ${theme.cardBackground};
  border-radius: ${theme.borderRadius};
  padding: 2rem;
  box-shadow: ${theme.boxShadow};
  border: 1px solid ${theme.borderColor};
  margin-bottom: 2rem;
  position: relative;
  z-index: 1;
  
  @media (max-width: 768px) {
    padding: 1.5rem;
  }
  
  @media (max-width: 480px) {
    padding: 1rem;
  }
`;

const SectionTitle = styled.h2`
  font-size: 1.5rem;
  font-weight: 600;
  color: ${theme.textColor};
  margin-bottom: 1.5rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  
  @media (max-width: 480px) {
    font-size: 1.25rem;
  }
`;

const PromptSection = styled.div`
  background: ${theme.secondaryGradient};
  border-radius: 0.75rem;
  padding: 1.5rem;
  margin-bottom: 2rem;
  border: 1px solid #bae6fd;
  
  @media (max-width: 768px) {
    padding: 1.25rem;
  }
  
  @media (max-width: 480px) {
    padding: 1rem;
  }
`;

const PromptInput = styled.textarea`
  width: 100%;
  min-height: 120px;
  padding: 1rem;
  border-radius: 0.5rem;
  border: 1px solid ${theme.borderColor};
  background: white;
  font-size: 1rem;
  font-family: inherit;
  resize: vertical;
  margin-bottom: 1rem;
  
  &:focus {
    outline: none;
    border-color: #3b82f6;
    box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.1);
  }
  
  @media (max-width: 480px) {
    min-height: 100px;
    font-size: 0.9rem;
  }
`;

const ActionButton = styled.button`
  background: ${theme.primaryGradient};
  color: white;
  border: none;
  padding: 0.75rem 1.5rem;
  border-radius: 0.5rem;
  font-size: 1rem;
  font-weight: 500;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  transition: all 0.2s ease;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  
  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.15);
  }
  
  &:disabled {
    opacity: 0.6;
    cursor: not-allowed;
    transform: none;
    box-shadow: none;
  }
  
  @media (max-width: 480px) {
    padding: 0.6rem 1rem;
    font-size: 0.9rem;
  }
`;

const SecondaryButton = styled.button`
  background: white;
  color: ${theme.textColor};
  border: 1px solid ${theme.borderColor};
  padding: 0.75rem 1.5rem;
  border-radius: 0.5rem;
  font-size: 1rem;
  font-weight: 500;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  transition: all 0.2s ease;
  
  &:hover {
    background: #f8fafc;
    transform: translateY(-1px);
  }
  
  &:disabled {
    opacity: 0.6;
    cursor: not-allowed;
    transform: none;
  }
  
  @media (max-width: 480px) {
    padding: 0.6rem 1rem;
    font-size: 0.9rem;
  }
`;

const ButtonGroup = styled.div`
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
  
  @media (max-width: 480px) {
    flex-direction: column;
    gap: 0.5rem;
  }
`;

const ChartPreview = styled.div`
  background: white;
  border-radius: 0.75rem;
  padding: 1.5rem;
  margin-top: 1.5rem;
  border: 1px solid ${theme.borderColor};
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.05);
  
  @media (max-width: 768px) {
    padding: 1.25rem;
  }
  
  @media (max-width: 480px) {
    padding: 1rem;
  }
`;

const ChartContainer = styled.div`
  background: #f8fafc;
  border-radius: 0.5rem;
  padding: 1rem;
  margin: 1rem 0;
  min-height: 300px;
  display: flex;
  align-items: center;
  justify-content: center;
  
  pre {
    max-width: 100%;
    overflow: auto;
    white-space: pre-wrap;
    word-wrap: break-word;
    font-size: 0.8rem;
  }
`;

const ErrorMessage = styled.div`
  background: #fee2e2;
  border: 1px solid #fecaca;
  color: #dc2626;
  padding: 1rem;
  border-radius: 0.75rem;
  margin: 1rem 0;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  
  @media (max-width: 480px) {
    padding: 0.75rem;
    font-size: 0.9rem;
  }
`;

function Charts() {
  const navigate = useNavigate();
  const [chartPrompt, setChartPrompt] = useState('');
  const [generatedCharts, setGeneratedCharts] = useState(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState(null);

  const handleGenerateCharts = async () => {
    if (!chartPrompt.trim()) {
      toast.error('Please describe what charts you want to generate');
      return;
    }

    setIsGenerating(true);
    setError(null);
    
    try {
      // Generate chart configurations using AI
      const chartResponse = await aiChatService.generateChartConfig(chartPrompt);
      
      // Handle different response structures
      let chartConfig = null;
      
      // Check if response has data property (from API)
      if (chartResponse && chartResponse.data) {
        chartConfig = chartResponse.data.chart_config || chartResponse.data;
      } 
      // Check if response directly contains chart_config
      else if (chartResponse && chartResponse.chart_config) {
        chartConfig = chartResponse.chart_config;
      }
      // Use the entire response as fallback
      else {
        chartConfig = chartResponse;
      }
      
      setGeneratedCharts(chartConfig);
      setIsGenerating(false);
      toast.success('AI-generated charts created successfully!');
    } catch (error) {
      console.error('Error generating charts:', error);
      setError('Failed to generate charts. Please check your OpenAI API key configuration.');
      setIsGenerating(false);
      // Show a sample chart configuration as fallback
      setGeneratedCharts({
        type: "bar",
        data: {
          labels: ["January", "February", "March", "April", "May"],
          datasets: [{
            label: "Sample Data",
            data: [12, 19, 3, 5, 2],
            backgroundColor: "rgba(54, 162, 235, 0.2)",
            borderColor: "rgba(54, 162, 235, 1)",
            borderWidth: 1
          }]
        },
        options: {
          responsive: true,
          plugins: {
            title: {
              display: true,
              text: "Sample Chart (Configure OpenAI API Key for Real Data)"
            }
          }
        }
      });
    }
  };

  const handleCreateDashboard = async () => {
    if (!chartPrompt.trim()) {
      toast.error('Please describe what dashboard you want to create');
      return;
    }

    try {
      // Navigate to builder with chart prompt
      navigate('/builder', { 
        state: { 
          userPrompt: `Create a dashboard with charts for: ${chartPrompt}`,
          projectAnalysis: {
            project_type: "dashboard",
            features: ["charts", "data_visualization", "analytics"]
          }
        }
      });
    } catch (error) {
      console.error('Error creating dashboard:', error);
      setError('Failed to create dashboard. Please try again.');
    }
  };

  return (
    <Container>
      <Header>
        <Title>AI Chart Generator</Title>
        <Subtitle>Create beautiful data visualizations with AI-powered chart generation</Subtitle>
      </Header>
      
      <Section>
        <SectionTitle>
          <BarChart3 size={24} />
          Generate AI-Powered Charts
        </SectionTitle>
        
        {error && (
          <ErrorMessage>
            <AlertCircle size={20} />
            {error}
          </ErrorMessage>
        )}
        
        <PromptSection>
          <h3>Describe your data visualization needs</h3>
          <p>Tell us what kind of charts you want to generate and what data they should represent.</p>
          
          <PromptInput
            value={chartPrompt}
            onChange={(e) => setChartPrompt(e.target.value)}
            placeholder="e.g., 'Create a bar chart showing monthly sales data for the past year' or 'Generate a pie chart of user demographics'"
          />
          
          <ButtonGroup>
            <ActionButton onClick={handleGenerateCharts} disabled={isGenerating || !chartPrompt.trim()}>
              {isGenerating ? (
                <>
                  <Loader size={16} />
                  Generating Charts...
                </>
              ) : (
                <>
                  <Zap size={16} />
                  Generate Charts
                </>
              )}
            </ActionButton>
            
            <SecondaryButton onClick={handleCreateDashboard} disabled={!chartPrompt.trim()}>
              <Play size={16} />
              Create Full Dashboard
            </SecondaryButton>
          </ButtonGroup>
        </PromptSection>
        
        {generatedCharts && (
          <ChartPreview>
            <h3>AI-Generated Chart Configurations</h3>
            <p>These Chart.js configurations were created by AI based on your request:</p>
            
            <ChartContainer>
              <pre>{JSON.stringify(generatedCharts, null, 2)}</pre>
            </ChartContainer>
            
            <p>
              When you generate a full application, these chart configurations will be automatically 
              integrated into your dashboard using Chart.js and react-chartjs-2.
            </p>
          </ChartPreview>
        )}
      </Section>
    </Container>
  );
}

export default Charts;
